-- AGENT MEMORY SEED — generated by scripts/_seed-emit-sql.js
-- Embeddings NULL — backfill via /api/agent-memory-backfill-embeddings
-- Idempotent: skips rows where (tenant, role, title) already exists.

-- 1: atlas | ElevenLabs 429 -> use scribe_v1 STT, not OpenAI Whisper
INSERT INTO public.agent_role_memory (tenant_id, agent_role, title, content, category, validation_status, tags, usage_count)
SELECT t.id, 'atlas', 'ElevenLabs 429 -> use scribe_v1 STT, not OpenAI Whisper', 'When ElevenLabs returns 429 on TTS/chat, its STT (scribe_v1) sub-quota usually still has headroom. Keep using /api/jarvis-voice?op=stt (ElevenLabs scribe_v1). Do NOT fall back to OpenAI Whisper unless ElevenLabs is fully exhausted — it adds latency and a paid API touch with no upside on quota errors.',
       'api_gotcha', 'auto', '["elevenlabs","429","stt","voice"]'::jsonb, 0
FROM public.tenants t
WHERE t.slug = 'heath'
  AND NOT EXISTS (SELECT 1 FROM public.agent_role_memory m WHERE m.tenant_id = t.id AND m.agent_role = 'atlas' AND m.title = 'ElevenLabs 429 -> use scribe_v1 STT, not OpenAI Whisper');

-- 2: atlas | VAD silenceMs 600ms is the sweet spot post-streaming-TTS
INSERT INTO public.agent_role_memory (tenant_id, agent_role, title, content, category, validation_status, tags, usage_count)
SELECT t.id, 'atlas', 'VAD silenceMs 600ms is the sweet spot post-streaming-TTS', 'After shipping the streaming chat+TTS pipeline, 800ms VAD silence felt sluggish on the Jarvis PWA. Heath asked for snappier turn-take. 600ms cuts the gap noticeably without false-fire on natural pauses. 1500ms is too long. Below 500ms produces premature cutoffs.',
       'voice_ux', 'auto', '["vad","jarvis","voice","latency"]'::jsonb, 0
FROM public.tenants t
WHERE t.slug = 'heath'
  AND NOT EXISTS (SELECT 1 FROM public.agent_role_memory m WHERE m.tenant_id = t.id AND m.agent_role = 'atlas' AND m.title = 'VAD silenceMs 600ms is the sweet spot post-streaming-TTS');

-- 3: atlas | Conversation history MUST order DESC + LIMIT + reverse
INSERT INTO public.agent_role_memory (tenant_id, agent_role, title, content, category, validation_status, tags, usage_count)
SELECT t.id, 'atlas', 'Conversation history MUST order DESC + LIMIT + reverse', 'When loading recent N messages from jarvis_messages, use order=created_at.desc + limit=N + slice().reverse() in JS. Loading ASC + LIMIT gives you the OLDEST N (every reply based on ancient context) instead of the most recent N. Heath called Jarvis a "conversational idiot" before this fix landed. See api/jarvis-voice.js handleChat() ~line 519.',
       'code_pattern', 'auto', '["supabase","pagination","jarvis","history"]'::jsonb, 0
FROM public.tenants t
WHERE t.slug = 'heath'
  AND NOT EXISTS (SELECT 1 FROM public.agent_role_memory m WHERE m.tenant_id = t.id AND m.agent_role = 'atlas' AND m.title = 'Conversation history MUST order DESC + LIMIT + reverse');

