INSERT INTO public.agent_role_memory (tenant_id, agent_role, title, content, category, validation_status, tags, usage_count)
SELECT t.id, 'atlas', 'Supabase realtime publication: only adds, never auto-includes new tables', 'New tables do NOT automatically join the supabase_realtime publication. After every CREATE TABLE that the PWA needs to subscribe to, add: `alter publication supabase_realtime add table public.<name>`. Symptoms when missed: client.channel().on("postgres_changes",...) listener never fires; UI shows stale data until next poll.',
       'external_service_quirk', 'auto', '["supabase","realtime","publication"]'::jsonb, 0
