INSERT INTO public.agent_role_memory (tenant_id, agent_role, title, content, category, validation_status, tags, usage_count)
SELECT t.id, 'atlas', 'pgvector ivfflat with 100 lists is fine up to ~50k rows', 'For agent_role_memory and similar small knowledge pools, ivfflat with lists=100 over a 1536-dim vector column gives sub-50ms nearest-neighbor search. Switch to hnsw or bump lists only if row count crosses ~50k OR query latency creeps over 200ms. Smaller datasets actually perform WORSE with more lists due to index sparsity.',
       'code_pattern', 'auto', '["pgvector","ivfflat","embeddings","supabase"]'::jsonb, 0
